mapper.select:
SELECT h.household_id AS householdId, h.dong, h.ho, COALESCE(latest.status, '공실') AS status, COUNT(DISTINCT v.vehicle_id) AS carCount, COUNT(DISTINCT CASE WHEN u.status = 'PENDING' AND u.is_deleted = false THEN u.user_id END) AS pendingCount, GREATEST(h.created_at, COALESCE(latest.changed_at, h.created_at)) AS lastChangedAt FROM household h
LEFT JOIN ( SELECT household_id, status, changed_at, ROW_NUMBER() OVER (PARTITION BY household_id ORDER BY changed_at DESC) AS rn FROM household_history ) latest ON latest.household_id = h.household_id AND latest.rn = 1
LEFT JOIN vehicle v ON v.household_id = h.household_id LEFT JOIN user u ON u.household_id = h.household_id
h.dong = #{dong}
AND h.ho LIKE CONCAT('%', #{ho}, '%')
AND COALESCE(latest.status, '공실') = #{status}
GROUP BY h.household_id, h.dong, h.ho, latest.status, latest.changed_at, h.created_at
ORDER BY pendingCount DESC, h.dong, CAST(h.ho AS UNSIGNED) LIMIT #{startIdx}, #{size}

SELECT COUNT(1) AS totalCount, CEIL(COUNT(1) / #{size}) AS maxPage FROM household h
h.dong = #{dong} AND h.ho LIKE CONCAT('%', #{ho}, '%')
AND COALESCE((SELECT hh.status FROM household_history hh WHERE hh.household_id = h.household_id ORDER BY hh.changed_at DESC LIMIT 1), '공실') = #{status}

SELECT COUNT(*)
FROM household
WHERE dong = #{dong}
  AND ho = #{ho}
